var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_QM","text":{"KOREA":"......미안하지만 그렇게는 안 되겠는데.","JPN":"……悪いけど、そういうわけにはいかないよ。","ENG":"Sorry, but I won’t allow it.","TWN":"……非常抱歉，但這可不行。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_QM","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"......?!","JPN":"……！？","ENG":"......?!","TWN":"……？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......넌?!","JPN":"……あなたは！？","ENG":"You?!","TWN":"……妳？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"잘 지냈어? 유미나.","JPN":"元気だった？　ヤナギ・ミナ。","ENG":"How have you been? Yoo Mina.","TWN":"妳好嗎？劉米娜。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"헤어진 지는 얼마 안 됐지만, 그래도 반가운걸?","JPN":"そんなに日は経ってないけど、それでも会えてうれしい。","ENG":"It hasn’t been that long since we last saw each other, but I’m still glad to see you again.","TWN":"雖然才剛分開沒多久，不過我應該還是很高興見到妳吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너...... 그 모습은 뭐야?","JPN":"あんた……その姿は何？","ENG":"You... What’s with the new look?","TWN":"妳……這個樣子是怎麼回事？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"아, 이거? 별거 아니야.","JPN":"あ、これ？　大したことないよ。","ENG":"Oh, this? It's nothing.","TWN":"喔，這個嗎？沒什麼。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"내가 가지고 있는 얼터너티브 인자에 리플레이서 간부들에게 제공하는 프로그레시브 인자를 합성했거든.","JPN":"私のオルタナティブ・ファクターをリプレイサー幹部に\\n与えられたプログレッシブ・ファクターと合成したの。","ENG":"I combined the Progressive Factor they provide to Replacer officers with my own Alternative Factor.","TWN":"我只是把我持有的可替代因子和克隆集團幹部提供的可操控因子進行了合成。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"굳이 이름 붙이자면...... 얼터그레시브 모드라고 해 둘까?","JPN":"あえて名前をつけるなら……オルタグレッシヴモード、でいいかな？","ENG":"I guess if we have to give it a name... We could call it the Altergressive mode?","TWN":"非要取個名字的話……叫替代進化體模式怎麼樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"우리 미나 양 같은 엘리트를 상대하려면 나도 이것저것 준비를 좀 해 둬야 하지 않겠어?","JPN":"ミナさんのようなエリートを相手するには、私もあれこれ準備しないといけないからね。","ENG":"After all, I should prepare myself if I am to face off with an elite closer like you, right?","TWN":"要和米娜小姐這樣的精英對抗，我總得做點準備吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"또 영문 모를 소릴......","JPN":"またワケのわからないことを……","ENG":"You've lost me again...","TWN":"又再說些莫名其妙的話……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그보다 왜 나타난 거지?","JPN":"それより、どうして現れたの？","ENG":"Anyway, what are you doing here?","TWN":"話說回來，妳為什麼會出現在這裡？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"설마 우릴 막으러 온 거야?","JPN":"まさか、私たちを阻止するために来たの？","ENG":"You’re not here to stop us, are you?","TWN":"難道是為了阻止我們嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"당연하잖아? 그럼 뭐, 티타임이라도 하러 나타난 줄 알았어?","JPN":"当たり前でしょ？　お茶しにきたわけじゃないしね。","ENG":"Of course I am. What, did you think I showed up for tea time or something?","TWN":"當然了！不然是來找妳們喝茶的嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"......동료들을 모두 배신한 주제에 그 뻔뻔한 태도는 대체 뭐야?","JPN":"……仲間全員を裏切ったくせに、厚かましいな。","ENG":"How could you be so shameless after you've betrayed all your teammates?","TWN":"……妳背叛了所有人，卻還一副問心無愧的態度，這是怎樣？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"넌 부끄러움이라는 것도 없어?","JPN":"あんたには恥ってものが無いわけ？","ENG":"Aren’t you even a little bit embarrassed?","TWN":"妳不知什麼叫羞恥嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"배신? 무슨 말인지 모르겠는데.","JPN":"裏切り？　何言ってるのかわからないんだけど。","ENG":"Betrayed? I don't know what you're talking about.","TWN":"背叛？我不懂你什麼意思。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"난 배신한 게 아니라 원래 있었던 곳으로 돌아간 것뿐이야.","JPN":"私は裏切ったのではなく、元の場所に戻っただけだよ。","ENG":"I didn’t betray anyone. I simply returned to where I was before.","TWN":"我不是背叛，只是回到原本的地方而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"뭐......?","JPN":"なっ……？","ENG":"What?","TWN":"什麼……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"설마 전혀 몰랐다고는 하지 않겠지?","JPN":"まさか、全然知らなかったとは言わないよね？","ENG":"Oh, don’t pretend like you didn’t see this coming at all.","TWN":"妳該不會完全不知道嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"우리가 리플레이서와 관계가 있었다는 걸.","JPN":"私たちがリプレイサーと関係があったということを。","ENG":"You knew we had something to do with the Syndicate.","TWN":"我們和克隆集團有關係的事情。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"알트 소대원을 아무도 데려오지 않은 걸 보면, 이미 짐작하고 있는 것 같은데?","JPN":"アルト小隊員は一切連れてきてないということは、すでに気づいてるんじゃない？","ENG":"Judging by the utter lack of ALT Squad members, it seems like you knew this already.","TWN":"看阿爾特小隊一個人都不在，你們應該已經預料到了吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그건.......","JPN":"それは……","ENG":"Well...","TWN":"這……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"말씀을 들어보니 역시 서윤 양은 리플레이서 출신이셨던 거군요.","JPN":"お話を聞く限り、やはりシズカさんはリプレイサー出身だったんですね。","ENG":"So it sounds like you were a Replacer after all.","TWN":"聽妳這麼說，徐芸小姐果然是克隆集團出身的吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그래.","JPN":"そうよ。","ENG":"That's right.","TWN":"是的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"하지만 이상하네요.","JPN":"だけど、おかしいですね。","ENG":"But that’s odd...","TWN":"但是，這還真奇怪呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이전에 싸웠던 리플레이서 나이트와 비숍의 태도를 봤을 때......","JPN":"この前戦ったリプレイサー・ナイトやビショップの様子からして……","ENG":"Given how the Replacer Knight and Bishop treated you before...","TWN":"從以前妳跟克隆·騎士和大主教戰鬥的態度來看……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서윤 양은 그들과 적대적인 관계라고 생각했습니다만?","JPN":"シズカさんは彼らと敵対関係にいると思いましたが。","ENG":"I would've thought you were in an antagonistic relationship with the Syndicate.","TWN":"我還以為徐芸小姐和他們是敵對關係呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"서로 손을 잡을 만한 상대로는 보이지 않았는데요.","JPN":"手を組むような相手には見えなかったんですよね。","ENG":"You didn’t exactly seem like you’d be partnering up with them.","TWN":"雙方看起來不像是會握手合作的夥伴啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"뭐...... 상호간의 이해가 일치했다고 해 둘게.","JPN":"まあ……お互いの利害が一致した、とだけ言っておくよ。","ENG":"Well... Let’s just say we found a point of mutual interest.","TWN":"這個嘛……畢竟雙方的利益是一致的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"내가 리플레이서를 필요로 하는 만큼, 리플레이서도 내가 필요했으니까.","JPN":"私がリプレイサーを必要としただけ、リプレイサーも私を必要としていたから。","ENG":"Just as much as I needed the Replacers, they needed me too.","TWN":"我需要克隆集團，克隆集團也需要我。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"이해의 일치라.......","JPN":"利害の一致ですか……","ENG":"Mutual interest, huh...","TWN":"利益一致……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"JOOSHIYOON_FENRIR_NULL_NULL","text":{"KOREA":"과연 어떤 이해가 일치했는지 궁금하네요.","JPN":"果たしてどんな利害が一致したのか、気になりますね。","ENG":"I’m curious what that mutual interest entails, exactly.","TWN":"我很好奇究竟是什麼樣的利益一致呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JOOSHIYOON_FENRIR_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"지금은 내 사생활이나 궁금해 할 때가 아니지 않을까?","JPN":"今は私の個人事情なんて気にしてる場合じゃないと思うけど？","ENG":"Now’s not the best time for you to be prying into my personal life, is it?","TWN":"現在不是對我的私事感到好奇的時候吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"더 중요한 일들이 있을 텐데. 예를 들어......","JPN":"もっと重要なことがあるはずだけどね。たとえば……","ENG":"I’m sure you've got more important things to do. For example...","TWN":"還有更重要的事情。比如……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"살아서 여길 빠져나갈 방법이라거나.","JPN":"ここからどうやって生きて帰るか、とか。","ENG":"Like getting out of here alive.","TWN":"活著從這裡出去的方法。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"HILDE_FENRIR_NULL_NULL","text":{"KOREA":"이 소리는......?","JPN":"この音は……？","ENG":"What’s that sound?","TWN":"這個聲音是……？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"긴급 보고입니다!","JPN":"緊急報告です！","ENG":"Priority report!","TWN":"緊急報告！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L11_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"적 침식체 및 리플레이서 혼성부대 11시, 4시, 7시 방향 출현!","JPN":"敵の侵食体とリプレイサーの混合部隊が11時、4時、7時の方向に出現！","ENG":"Composite units of C.O.'s and Replacers have appeared at your 11, 4, and 7 o' clock!","TWN":"11點、4點、7點方向出現了侵蝕體和克隆集團的混合部隊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"......포위당했습니다!","JPN":"取り囲まれました！","ENG":"We're surrounded!","TWN":"……我們被包圍了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"HILDE_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"뭐? 어느새......","JPN":"なんですって！　いつの間に……","ENG":"Huh? When did they...","TWN":"什麼？是什麼時候……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"......함정이군요.","JPN":"……罠ですね。","ENG":"So it was a trap.","TWN":"……是一個陷阱呢。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"이 정도의 병력이 우연히 매복하고 있었을 리는 없으니까요.","JPN":"これ程の兵力が、たまたま待ち伏せしているはずはありませんから。","ENG":"It’s highly unlikely so many troops would just happen to be ambushing here.","TWN":"這麼多的兵力不可能是碰巧埋伏在這裡的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"맞아. 내가 다른 건 몰라도 촉이 좀 좋은 편이거든.","JPN":"そうよ。私、他のことはともかく、勘はいい方なんだ。","ENG":"Correct. I've got a pretty good instinct for these sort of things, you see.","TWN":"是的。我雖然不知道別的事情，但第六感還是蠻準的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"너희와 헤어질 때 리플레이서 비숍 재생체의 태도가 아무래도 수상해서 말이야.","JPN":"君たちと別れるときのリプレイサー・ビショップ再生体の態度がどうも怪しくてね。","ENG":"I thought there was something fishy about the way the regenerated Replacer Bishop was acting when she was leaving.","TWN":"和你們分開的時候，克隆·大主教再生體的樣子不管怎麼看，都太奇怪了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"여길 찾아낸 걸 보면 아마 그녀가 너희에게 정보를 흘린 거겠지?","JPN":"ここを見つけたということは、たぶん彼女があんたたちに情報を流したんだろうね。","ENG":"Seeing that you’re here, I bet she leaked the intel to you, huh?","TWN":"你們能找到這裡，應該是那個女人洩漏了情報吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":".......","JPN":"……","ENG":".......","TWN":"……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L25_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"하지만 그렇다고 해도 이상하군요.","JPN":"しかし、そうだとしてもおかしいですね。","ENG":"Still, something seems rather off here.","TWN":"但就算這樣也很奇怪。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"전향한 지 얼마 되지도 않은 당신에게 이 정도의 병력을 움직일 권한은 없을 텐데요?","JPN":"くら替えして間もないあなたに、これほどの兵力を動かす権限はないと思いますが。","ENG":"Surely they wouldn’t grant you the authority to mobilize this many troops when you’ve just recently defected.","TWN":"妳叛變還沒多久，怎麼可能有調動這麼多兵力的權限？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"KYLE_DELTA_NULL_NULL","text":{"KOREA":"설마 이건...... 당신의 독단입니까?","JPN":"まさかこれは…あなたの独断ですか？","ENG":"Or could this be... an independent decision of yours?","TWN":"難道這是……妳獨斷的行動？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L29_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"......맞아. 사실 무리를 좀 하긴 했지.","JPN":"……そうだよ。実はちょっと無理したのよね。","ENG":"You’re right. I am pushing it here a bit.","TWN":"……沒錯。實際上是有點勉強。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"하지만 당신 말대로 전향자인 내가 인정을 받으려면 약간의 위험은 감수해야 하는 것 아니겠어?","JPN":"でもあんたの言う通り、くら替えした私のことを認めてもらうには、多少のリスクは覚悟しないとね？","ENG":"But like you said, a fresh defector like me ought to take a little risk to win recognition from my new bosses, don’t you think?","TWN":"但就像你所說的，像我這樣的叛變者如果想要被認可，不就必須要承受這些風險嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"결과적으로 보면 괜찮은 배팅을 한 것 같은데.","JPN":"結果的に、いいバッティングだと思うけど。","ENG":"At the end of the day, I think I bet my chips pretty wisely here.","TWN":"從結果上來看，是我賭對了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"비숍 재생체의 배신을 알아내고, 너희들까지 처리하면......","JPN":"ビショップ再生体の裏切りを突き止めて、君たちまで始末したら……","ENG":"If I expose the Regenerated Bishop’s betrayal and take you all out too...","TWN":"不但打探出大主教再生體的背叛，還能處理掉你們……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"리플레이서 조직 안에서 내 지위도 꽤 올라갈 거야.","JPN":"リプレイサー組織での私の地位も、かなり上がるはずよね。","ENG":"My standing in the Syndicate will skyrocket for sure.","TWN":"這樣一來，我在克隆集團組織內部地位就會上升不少吧。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"이봐, 아가씨. 정말 이대로 끝까지 가 볼 생각이야?","JPN":"ちょっと、あんたね。本当にこのまま最後までやるつもりなの？","ENG":"Come on, girl. You really wanna go all the way with this?","TWN":"喂！小姐，妳真的要一直這樣下去嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"지금이라도 늦지 않았어.","JPN":"今からでも遅くないよ？","ENG":"It’s not too late you know.","TWN":"現在還不算太晚。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"SYLVIA_DELTA_NULL_NULL","text":{"KOREA":"병력을 물리고 다시 돌아온다면, 정상참작의 여지가......","JPN":"兵力を退けて戻ってくるなら、情状酌量の余地が……","ENG":"If you call off the troops and return to us, I’m sure we can consider leniency...","TWN":"要是妳撤兵回到我們這裡的話，還有對妳酌情處理的餘地……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SYLVIA_DELTA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"KYLE_DELTA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"하하하.","JPN":"アハハ。","ENG":"Hahaha...","TWN":"哈哈哈。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그런 이야기는 불멸체 코어를 파괴하고 난 다음에나 하는 게 좋지 않을까?","JPN":"そんな話はコアを破壊した後にした方がいいんじゃない？","ENG":"Why don’t you save that gibberish for after you destroy the core?","TWN":"這種話等你們破壞了不滅者核心再跟我說，不是比較好嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"지금 코너에 몰린 건 누가 봐도 그쪽인데 말이지.","JPN":"今、追い詰められているのは、誰が見てもそっちなのにね。","ENG":"Clearly, you're the ones who are cornered right now.","TWN":"現在被逼到絕境的，不管怎麼看都是你們啊。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"누가 코너에 몰렸다는 거야?","JPN":"誰が追い詰められてるって？","ENG":"Cornered? Us?","TWN":"誰被逼到絕境了？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"인자 전송기인가 하는 것도 이미 파괴됐어.","JPN":"ファクター伝送機とやらも、既に破壊済みだよ。","ENG":"Your factor transmitter thingy's already destroyed.","TWN":"因子傳輸機已經被我們破壞了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"코너에 몰린 건 너라고.","JPN":"追い詰められているのはあんたの方だから。","ENG":"You’re the one who's cornered.","TWN":"被逼到絕境的是妳。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"기대를 깨서 미안하지만, 리플레이서 인자 전송기 따윈 얼마든지 새로 만들 수 있어.","JPN":"期待外れで申し訳ないけど、リプレイサー・ファクター伝送機なんか、いくらでも作り直せるよ。","ENG":"I’d hate to burst your bubble, but we can always make a new Replacer Factor transmitter.","TWN":"很抱歉讓妳失望了，克隆因子傳輸機這種東西，想做多少就做多少……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"시간이 좀 걸리긴 하겠지만...... 그뿐이야.","JPN":"時間はちょっとかかるでしょうけど……それだけの話。","ENG":"Sure, it would take some time... but that’s all it is.","TWN":"可能會花點時間……但僅此而已。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"불멸체 코어만 무사하다면 바뀐 건 아무것도 없어.","JPN":"不滅体コアさえ無事ならば、何も変わりやしない。","ENG":"Nothing will change as long as the Immortal System Core is intact.","TWN":"只要不滅者核心沒事，就什麼都不會改變。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"그렇다면...... 그것까지 부숴 버리면 되겠군.","JPN":"なら……それもぶっ壊してしまえばいいんだね。","ENG":"If that’s how it is... I guess we’ll just smash that too.","TWN":"既然這樣……那就把那個也一起毀掉。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L1_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"너 혼자서 우릴 막을 수 있을 것 같아?","JPN":"あんた一人で私たちを阻止できると思う？","ENG":"You think you can stop us all by yourself?","TWN":"妳認為妳一個人可以擋住我們嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그럴 리가?","JPN":"まさか。","ENG":"Oh, of course not.","TWN":"怎麼可能？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"너희들의 실력은 옆에서 지켜보던 내가 가장 잘 알고 있어.","JPN":"あなたたちの実力はそばで見ていた私が一番よく知っている。","ENG":"I’ve watched you fight closely by your side. I know what you're capable of more than anyone else here.","TWN":"身為旁觀者的我對你們的實力再清楚不過了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그런 내가 너희들과 정면으로 싸우는 바보 같은 짓을 할 리가 있겠어?","JPN":"そんな私が、あなたたちと真向勝負なんて、そんなバカなことしないよ。","ENG":"So I’d be a fool to fight you head-on, wouldn’t I?","TWN":"我怎麼會做這種和你們正面對決的傻事呢？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"이것들은 전부 시간 벌이용이야.","JPN":"これらは全部、時間稼ぎのため。","ENG":"This is just for buying more time.","TWN":"這全是為了爭取時間。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"간부들이 돌아올 때까지 버티기만 한다면 뒷일은 그쪽에서 알아서 하겠지.","JPN":"幹部が戻ってくるまで粘れさえすれば、後のことはなんとかしてくれるでしょう。","ENG":"As long as I can hold my ground until the officers come, they’ll take care of the rest.","TWN":"我只要堅持到幹部們過來這裡，剩下的事情他們自己會看著辦。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"정말...... 해보자는 거지?","JPN":"本気で……戦うつもりなのね？","ENG":"So... That's how you want to play, huh?","TWN":"妳真的……要試試看是吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"물론이야.","JPN":"もちろん。","ENG":"Of course.","TWN":"當然了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"너처럼 운이 좋은 사람은 어떤지 모르겠지만, 난 언제나 진지하다고.","JPN":"あなたみたいに運のいい人はまた別かもしれないけど、私はいつだって真剣なんだから。","ENG":"Lucky girls like you might not understand, but I’m always dead serious about these things.","TWN":"像妳這麼幸運的人應該不會知道吧，但我不管什麼時候都是很認真的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"YOOMINA_FENRIR_NULL_NULL","text":{"KOREA":"이 자식.......","JPN":"こいつ……","ENG":"Why you little...","TWN":"妳這傢伙……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"YOOMINA_FENRIR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그럼 다들 최선을 다해서 살아남아 보세요.","JPN":"じゃあ、みんな最善を尽くして生き残ってみてね。","ENG":"Alright then. Best of luck to you all.","TWN":"那你們就盡全力地活下來吧！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"만약 포위를 뚫고 불멸체 코어까지 도착한다면......","JPN":"もし包囲網を突き破って、不滅体コアまでたどり着いたら……","ENG":"If you manage to break through the siege and reach the Immortal System Core...","TWN":"如果你們突破包圍，到達不滅者核心附近的話……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"그때는 제가 직접 상대해 드리죠.","JPN":"その時は私が相手をしてあげましょう。","ENG":"I’ll do you the honor of fighting you myself.","TWN":"到時候我會親自來當你們的對手。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"물론 그럴 만한 여력이 남아 있다면 말이지만요.","JPN":"もちろん、その分の余力があるなら、の話ですが。","ENG":"That is, if you still got enough fuel in your tank by then.","TWN":"當然，前提是你們還有餘力的話。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_REPLACER_NULL_NULL","text":{"KOREA":"......하하하.","JPN":"……アハハ。","ENG":"Hahaha...","TWN":"……哈哈哈。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_REPLACER_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"적 병력, 접근!","JPN":"敵の兵力、接近中！","ENG":"Enemy troops approaching!","TWN":"敵方部隊，接近！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"LENA_COFFIN_NULL_NULL","text":{"KOREA":"어, 엄청난 수량입니다!","JPN":"も、ものすごい数です！","ENG":"T-there's so many of them!","TWN":"數、數量太多了！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_REPLACER","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENA_COFFIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};